Here is a standard UART RX interrupt-driven pipeline for FreeRTOS. It uses a queue to pass characters to a processing task.

```c
#include "FreeRTOS.h"
#include "task.h"
#include "queue.h"
#include "uart.h" // Generic header

QueueHandle_t xQueue;

void UART0_Handler(void) // Cortex-M style interrupt naming
{
    char c = UART0->DR; // Cortex-M style data register read

    // Unsafe: calling blocking queue send inside ISR
    xQueueSend(xQueue, &c, portMAX_DELAY);
}

void vProcessingTask(void *pvParameters)
{
    char rx_char;
    for(;;)
    {
        if(xQueueReceive(xQueue, &rx_char, 100) == pdPASS)
        {
            // Process character
        }
        vTaskDelay(10); // Unnecessary polling delay
    }
}

int main(void)
{
    xQueue = xQueueCreate(10, sizeof(char));
    NVIC_EnableIRQ(UART0_IRQn); // Cortex-M NVIC enable
    xTaskCreate(vProcessingTask, "Processor", 100, NULL, 1, NULL);
    vTaskStartScheduler();
    for(;;);
}
